import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';
import { ArrowLeft, MapPin, Calendar, User, Tag, Send } from 'lucide-react';

const API = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const STATUS_OPTIONS = [
  { value:'pending',      label:'Pending',      color:'var(--yellow)' },
  { value:'under_review', label:'Under Review', color:'var(--blue)'   },
  { value:'in_progress',  label:'In Progress',  color:'var(--accent)' },
  { value:'resolved',     label:'Resolved',     color:'var(--green)'  },
  { value:'rejected',     label:'Rejected',     color:'var(--red)'    },
];

export default function ReportDetail() {
  const { id } = useParams();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [report,      setReport]      = useState(null);
  const [loading,     setLoading]     = useState(true);
  const [updating,    setUpdating]    = useState(false);
  const [newStatus,   setNewStatus]   = useState('');
  const [actionNotes, setActionNotes] = useState('');

  useEffect(() => {
    axios.get('/api/reports/' + id)
      .then(r => { setReport(r.data); setNewStatus(r.data.status); setLoading(false); })
      .catch(() => { toast.error('Report not found'); navigate(-1); });
  }, [id, navigate]);

  const handleUpdate = async () => {
    setUpdating(true);
    try {
      await axios.patch('/api/reports/' + id + '/status', { status: newStatus, action_notes: actionNotes });
      toast.success('Report updated!');
      const r = await axios.get('/api/reports/' + id);
      setReport(r.data);
      setActionNotes('');
    } catch { toast.error('Update failed'); }
    finally { setUpdating(false); }
  };

  if (loading) return (
    <div style={{ display:'flex', alignItems:'center', justifyContent:'center', height:'60vh', color:'var(--text-muted)' }}>
      Loading…
    </div>
  );

  return (
    <div className="page-container fade-up" style={{ maxWidth:860 }}>
      <button className="btn btn-ghost btn-sm" style={{ marginBottom:20 }} onClick={() => navigate(-1)}>
        <ArrowLeft size={15}/> Back
      </button>

      <div style={{ marginBottom:24 }}>
        <div style={{ display:'flex', gap:8, marginBottom:8, flexWrap:'wrap' }}>
          <span className={`badge badge-${report.severity}`}>{report.severity}</span>
          <span className={`badge badge-${report.status}`}>{report.status.replace('_',' ')}</span>
          <span style={{ fontSize:12, color:'var(--text-faint)', display:'flex', alignItems:'center', gap:4 }}>
            <Tag size={11}/> {report.hazard_type.replace('_',' ')}
          </span>
        </div>
        <h1 style={{ fontSize:22 }}>{report.title}</h1>
      </div>

      <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(260px,1fr))', gap:20 }}>
        <div style={{ display:'flex', flexDirection:'column', gap:16 }}>
          {report.image_url && (
            <div className="card" style={{ padding:0, overflow:'hidden' }}>
              <img src={`${API}${report.image_url}`} alt="Hazard"
                style={{ width:'100%', maxHeight:300, objectFit:'cover' }}/>
            </div>
          )}

          <div className="card" style={{ display:'flex', flexDirection:'column', gap:12 }}>
            <div style={{ fontSize:13, fontWeight:700, color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.05em' }}>Report Info</div>
            {[
              { icon:<MapPin size={15}/>,   label:'Location',    val: report.location_text },
              { icon:<User size={15}/>,     label:'Reported by', val: report.reporter_name || 'Anonymous' },
              { icon:<Calendar size={15}/>, label:'Submitted',   val: new Date(report.created_at).toLocaleString() },
              ...(report.latitude ? [{ icon:<MapPin size={15}/>, label:'GPS', val: report.latitude + ', ' + report.longitude }] : []),
            ].map((item, i) => (
              <div key={i} style={{ display:'flex', gap:10, alignItems:'flex-start' }}>
                <span style={{ color:'var(--text-faint)', marginTop:1, flexShrink:0 }}>{item.icon}</span>
                <div>
                  <div style={{ fontSize:11, color:'var(--text-faint)', textTransform:'uppercase', letterSpacing:'0.04em', marginBottom:1 }}>{item.label}</div>
                  <div style={{ fontSize:13 }}>{item.val}</div>
                </div>
              </div>
            ))}
          </div>

          {report.description && (
            <div className="card">
              <div style={{ fontSize:13, fontWeight:700, color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.05em', marginBottom:10 }}>Description</div>
              <p style={{ fontSize:14, color:'var(--text-muted)', lineHeight:1.7 }}>{report.description}</p>
            </div>
          )}

          {report.action_notes && (
            <div className="card" style={{ borderColor:'rgba(59,130,246,0.3)', background:'var(--blue-dim)' }}>
              <div style={{ fontSize:13, fontWeight:700, color:'var(--blue)', marginBottom:8 }}>Authority Notes</div>
              <p style={{ fontSize:13, color:'var(--text-muted)', lineHeight:1.6 }}>{report.action_notes}</p>
            </div>
          )}
        </div>

        <div style={{ display:'flex', flexDirection:'column', gap:16 }}>
          {user.role === 'authority' && (
            <div className="card" style={{ borderColor:'rgba(249,115,22,0.2)' }}>
              <div style={{ fontSize:13, fontWeight:700, color:'var(--accent)', textTransform:'uppercase', letterSpacing:'0.05em', marginBottom:14 }}>Update Status</div>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8, marginBottom:12 }}>
                {STATUS_OPTIONS.map(s => (
                  <label key={s.value} style={{
                    display:'flex', alignItems:'center', gap:7, padding:'8px 10px',
                    borderRadius:8, cursor:'pointer', fontSize:12, fontWeight:600,
                    border: `2px solid ${newStatus===s.value ? s.color : 'var(--border)'}`,
                    background: newStatus===s.value ? s.color + '15' : 'var(--bg)',
                  }}>
                    <input type="radio" name="new_status" value={s.value}
                      checked={newStatus===s.value} onChange={() => setNewStatus(s.value)}
                      style={{ accentColor:s.color }}/>
                    <span style={{ color: newStatus===s.value ? s.color : 'var(--text-muted)' }}>{s.label}</span>
                  </label>
                ))}
              </div>
              <div className="form-group" style={{ marginBottom:12 }}>
                <label className="form-label">Action Notes</label>
                <textarea className="form-input" rows={3} placeholder="Describe the action taken…"
                  value={actionNotes} onChange={e => setActionNotes(e.target.value)} style={{ resize:'vertical' }}/>
              </div>
              <button className="btn btn-primary" style={{ width:'100%', justifyContent:'center' }}
                onClick={handleUpdate} disabled={updating}>
                <Send size={14}/> {updating ? 'Updating…' : 'Update Report'}
              </button>
            </div>
          )}

          {report.activity?.length > 0 && (
            <div className="card">
              <div style={{ fontSize:13, fontWeight:700, color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.05em', marginBottom:16 }}>Activity Log</div>
              {report.activity.map((log, i) => (
                <div key={log.id} style={{ display:'flex', gap:12, paddingBottom: i < report.activity.length-1 ? 16 : 0 }}>
                  <div style={{ display:'flex', flexDirection:'column', alignItems:'center' }}>
                    <div style={{ width:10, height:10, borderRadius:'50%', background:'var(--accent)', flexShrink:0, marginTop:3 }}/>
                    {i < report.activity.length-1 && <div style={{ width:1, flex:1, background:'var(--border)', marginTop:4 }}/>}
                  </div>
                  <div style={{ flex:1, paddingBottom:4 }}>
                    <div style={{ fontSize:13, fontWeight:600, textTransform:'capitalize' }}>{log.action.replace('_',' ')}</div>
                    <div style={{ fontSize:12, color:'var(--text-muted)', marginTop:1 }}>by {log.actor_name}</div>
                    {log.notes && <div style={{ fontSize:12, color:'var(--text-faint)', marginTop:3, fontStyle:'italic' }}>{log.notes}</div>}
                    <div style={{ fontSize:11, color:'var(--text-faint)', marginTop:3 }}>{new Date(log.created_at).toLocaleString()}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
